// Orders is the resolver for the Orders field.
func (r *queryResolver) Orders(ctx context.Context, input model.QueryOrdersInput) (*model.OrdersConnection, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	if len(input.AccountID) == 0 {
		return nil, mowerror.New(mowerror.InvalidArgument, "accountId is required")
	}

	hasFinStart := input.FinishedStartTsMs != nil
	hasFinEnd := input.FinishedEndTsMs != nil
	if hasFinStart != hasFinEnd {
		return nil, mowerror.New(mowerror.InvalidArgument, "finishedStartTsMs and finishedEndTsMs must both be set or both omitted")
	}
	if hasFinStart && !input.IncludeFinished {
		return nil, mowerror.New(mowerror.InvalidArgument, "includeFinished must be true when filtering by finished time range")
	}

	request := &ctypes.QueryOrdersByPageRequest{
		AccountID: input.AccountID,
		Page:      int32(input.Page),
		Size:      int32(input.Size),
	}
	if input.Symbol != nil {
		request.Symbol = *input.Symbol
	}
	if input.OrderType != nil {
		switch *input.OrderType {
		case model.OrderTypeMarket:
			request.OrderType = lo.ToPtr(ctypes.OrderTypeMarket)
		case model.OrderTypeLimit:
			request.OrderType = lo.ToPtr(ctypes.OrderTypeLimit)
		case model.OrderTypeNone:
			request.OrderType = lo.ToPtr(ctypes.OrderTypeUnknown)
		}
	}
	if input.OrderSource != nil {
		switch *input.OrderSource {
		case model.OrderSourceUser:
			request.OrderSource = lo.ToPtr(ctypes.OrderSourceUser)
		case model.OrderSourceStrategy:
			request.OrderSource = lo.ToPtr(ctypes.OrderSourceStrategy)
		case model.OrderSourceLiquidation:
			request.OrderSource = lo.ToPtr(ctypes.OrderSourceLiquidation)
		case model.OrderSourceAdl:
			request.OrderSource = lo.ToPtr(ctypes.OrderSourceADL)
		}
	}
	if !input.IncludeFinished {
		request.Statuses = []ctypes.OrderStatus{
			ctypes.OrderStatusNew,
			ctypes.OrderStatusPending,
			ctypes.OrderStatusWorking,
			ctypes.OrderStatusPartialDone,
		}
	}
	if hasFinStart {
		fs := int64(*input.FinishedStartTsMs)
		fe := int64(*input.FinishedEndTsMs)
		request.FinishedStartTsMs = &fs
		request.FinishedEndTsMs = &fe
	}

	response, err := r.OrderSvc.QueryOrdersByPage(ctx, request)
	if err != nil {
		return nil, err
	}

	orders := make([]*model.Order, 0, len(response.Orders))
	for _, o := range response.Orders {
		if oo := converter.OrderTypes2Gql(o); oo != nil {
			orders = append(orders, oo)
		}
	}

	totalCount := int(response.TotalCount)
	result := &model.OrdersConnection{
		List:       orders,
		TotalCount: totalCount,
	}
	return result, nil
}

