// EstimateOrder is the resolver for the EstimateOrder field.
func (r *queryResolver) EstimateOrder(ctx context.Context, input model.EstimateOrderInput) (*model.EstimateOrderResult, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}

	if strings.TrimSpace(input.AccountID) == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "accountId is required")
	}
	if strings.TrimSpace(input.Symbol) == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "symbol is required")
	}
	if strings.TrimSpace(input.Notional) == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "notional is required")
	}
	if strings.TrimSpace(input.Price) == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "price is required")
	}

	side := ctypes.PositionSideLong
	switch input.Side {
	case model.PositionSideLong:
		side = ctypes.PositionSideLong
	case model.PositionSideShort:
		side = ctypes.PositionSideShort
	default:
		return nil, mowerror.New(mowerror.InvalidArgument, "side is required")
	}

	req := &ctypes.EstimateOrderRequest{
		AccountID: input.AccountID,
		Symbol:    input.Symbol,
		Side:      side,
		IsBuy:     input.IsBuy,
		OrderType: ctypes.OrderType(input.OrderType),
		Price:     input.Price,
		QuoteQty:  input.Notional,
	}
	if input.Leverage != nil {
		req.Leverage = int32(*input.Leverage)
	}

	resp, err := r.AccountSvc.EstimateOrder(ctx, req)
	if err != nil {
		return nil, err
	}
	if resp == nil {
		return &model.EstimateOrderResult{}, nil
	}

	var liquidationPricePtr, feePtr, feeAssetPtr, expectedPnlPtr *string
	if lp := strings.TrimSpace(resp.LiquidationPrice); lp != "" {
		liquidationPricePtr = &lp
	}
	if f := strings.TrimSpace(resp.Fee); f != "" {
		feePtr = &f
	}
	if fa := strings.TrimSpace(resp.FeeAsset); fa != "" {
		feeAssetPtr = &fa
	}
	if pnl := strings.TrimSpace(resp.ExpectedPnl); pnl != "" {
		expectedPnlPtr = &pnl
	}

	return &model.EstimateOrderResult{
		LiquidationPrice: liquidationPricePtr,
		Fee:              feePtr,
		FeeAsset:         feeAssetPtr,
		ExpectedPnl:      expectedPnlPtr,
	}, nil
}

